// ── RANDOM DAILY BANNER ROTATION ──
// Uses a date-seeded shuffle so banners change daily but stay consistent within a day
function rotateDailyBanners(){
  const bannerKeys = Object.keys(SL_BANNERS);
  if(bannerKeys.length < 4) return;
  const today = new Date().toDateString();
  // Simple date-based seed for deterministic daily shuffle
  let seed = 0;
  for(let i=0;i<today.length;i++) seed = ((seed << 5) - seed + today.charCodeAt(i)) | 0;
  function seededRand(){ seed = (seed * 16807 + 0) % 2147483647; return (seed & 0x7fffffff) / 2147483647; }
  // Shuffle banner keys using seeded random
  const shuffled = [...bannerKeys];
  for(let i = shuffled.length - 1; i > 0; i--){
    const j = Math.floor(seededRand() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  // Assign to each screen banner
  const targets = ['ban-home','ban-stats','ban-shop','ban-prof'];
  targets.forEach((id, idx) => {
    const el = document.getElementById(id);
    if(el && SL_BANNERS[shuffled[idx % shuffled.length]]){
      el.src = SL_BANNERS[shuffled[idx % shuffled.length]];
    }
  });
}

